// The baked-in demo teams belong to Middletown; give them their club identity.
function withSeedClub(teams) {
  return (teams || []).map((t) => (t.clubName == null && (t.id === "t_senior" || t.id === "t_u21")) ? { ...t, clubName: "Middletown", clubIrish: "Coillidh Chanannáin" } : t);
}
function makeSeed() {
  const s = JSON.parse(SEED_STATE_JSON);
  s.settings = { ...DEFAULT_SETTINGS, ...(s.settings || {}) };
  s.teams = withSeedClub(s.teams);
  return s;
}

/* ============================ persistence ============================ */

const STORE_KEY = "gaa_coach_hub_v2";
// Persists to the phone's own storage (localStorage). Async interface kept so the
// rest of the app is unchanged. Data lives only on this device — export backups regularly.
const store = {
  async get(k) {
    try { if (typeof localStorage !== "undefined") return localStorage.getItem(k); } catch (_) {}
    return null;
  },
  // Returns true on success. A false result almost always means the phone's
  // storage is full (too many photos) — the app surfaces a warning so a save
  // never fails silently.
  async set(k, v) {
    try { if (typeof localStorage !== "undefined") { localStorage.setItem(k, v); return true; } } catch (_) { return false; }
    return false;
  },
};

/* ============================ reducer ============================ */

function reducer(state, action) {
  switch (action.type) {
    case "HYDRATE": return action.state;
    case "RESET": return makeSeed();

    case "ADD_TEAM": {
      const id = "t" + Date.now();
      return { ...state, teams: [...state.teams, { id, ...action.team }], activeTeamId: id };
    }
    case "SET_ACTIVE_TEAM": return { ...state, activeTeamId: action.id };
    case "UPDATE_TEAM":
      return { ...state, teams: state.teams.map((t) => (t.id === action.id ? { ...t, ...action.patch } : t)) };

    case "DELETE_TEAM": {
      const tid = action.id;
      const teams = state.teams.filter((t) => t.id !== tid);
      if (!teams.length) return state; // never remove the last team
      const removedFixtureIds = new Set(state.fixtures.filter((f) => f.teamId === tid).map((f) => f.id));
      const removedSessionIds = new Set(state.sessions.filter((s) => s.teamId === tid).map((s) => s.id));
      const removedPlayerIds = new Set(state.players.filter((p) => p.teamId === tid).map((p) => p.id));
      const prune = (obj, ids) => { const o = { ...(obj || {}) }; ids.forEach((id) => delete o[id]); return o; };
      return {
        ...state,
        teams,
        players: state.players.filter((p) => p.teamId !== tid),
        fixtures: state.fixtures.filter((f) => f.teamId !== tid),
        sessions: state.sessions.filter((s) => s.teamId !== tid),
        lineups: prune(state.lineups, removedFixtureIds),
        availability: prune(state.availability, new Set([...removedFixtureIds, ...removedSessionIds])),
        attendance: prune(state.attendance, removedSessionIds),
        events: prune(state.events, removedFixtureIds),
        liveMatches: prune(state.liveMatches, removedFixtureIds),
        subOrders: prune(state.subOrders, removedFixtureIds),
        extraWork: prune(state.extraWork, removedPlayerIds),
        activeTeamId: state.activeTeamId === tid ? teams[0].id : state.activeTeamId,
      };
    }

    case "ADD_PLAYER": {
      const id = "p" + Date.now();
      return { ...state, players: [...state.players, { id, teamId: state.activeTeamId, injured: false, injuryNote: "", notes: "", ...action.player }] };
    }
    case "ADD_PLAYERS": {
      const base = Date.now();
      const added = action.players.map((pl, i) => ({ id: "p" + base + "_" + i, teamId: state.activeTeamId, injured: false, injuryNote: "", notes: "", ...pl }));
      return { ...state, players: [...state.players, ...added] };
    }
    case "UPDATE_PLAYER": {
      // Captaincy is per-player: setting one player's role never clears anyone
      // else's, so a team can carry several captains / vice-captains.
      return { ...state, players: state.players.map((p) => (p.id === action.id ? { ...p, ...action.patch } : p)) };
    }
    case "DELETE_PLAYER": {
      const lineups = {};
      for (const [fid, lu] of Object.entries(state.lineups)) {
        const n = { ...lu };
        for (const k of Object.keys(n)) if (n[k] === action.id) n[k] = null;
        lineups[fid] = n;
      }
      return { ...state, players: state.players.filter((p) => p.id !== action.id), lineups };
    }
    case "MOVE_PLAYER": {
      const players = [...state.players];
      const me = players.find((p) => p.id === action.id);
      if (!me) return state;
      const mates = players.filter((p) => p.teamId === me.teamId && p.group === me.group);
      const gi = mates.findIndex((p) => p.id === action.id);
      const target = mates[gi + action.dir];
      if (!target) return state;
      const ai = players.findIndex((p) => p.id === me.id);
      const bi = players.findIndex((p) => p.id === target.id);
      const tmp = players[ai]; players[ai] = players[bi]; players[bi] = tmp;
      return { ...state, players };
    }
    case "SEEN_HINT":
      return { ...state, hints: { ...(state.hints || {}), [action.key]: true } };
    case "RESTORE_FIXTURE": {
      const { fixture, lineup, events, availability } = action.snapshot;
      return {
        ...state,
        fixtures: [...state.fixtures, fixture],
        lineups: lineup ? { ...state.lineups, [fixture.id]: lineup } : state.lineups,
        events: events ? { ...state.events, [fixture.id]: events } : state.events,
        availability: availability ? { ...state.availability, [fixture.id]: availability } : state.availability,
      };
    }
    case "RESTORE_SESSION": {
      const { session, attendance, availability } = action.snapshot;
      return {
        ...state,
        sessions: [...state.sessions, session],
        attendance: attendance ? { ...state.attendance, [session.id]: attendance } : state.attendance,
        availability: availability ? { ...state.availability, [session.id]: availability } : state.availability,
      };
    }
    case "SAVE_LIVE":
      return { ...state, liveMatches: { ...(state.liveMatches || {}), [action.fixtureId]: action.data } };
    case "CLEAR_LIVE": {
      const lm = { ...(state.liveMatches || {}) }; delete lm[action.fixtureId];
      return { ...state, liveMatches: lm };
    }
    case "SET_SETTINGS":
      return { ...state, settings: { ...(state.settings || DEFAULT_SETTINGS), ...action.patch } };
    case "ADD_EXTRA_WORK":
      return { ...state, extraWork: { ...(state.extraWork || {}), [action.playerId]: [action.entry, ...((state.extraWork || {})[action.playerId] || [])] } };
    case "DELETE_EXTRA_WORK":
      return { ...state, extraWork: { ...(state.extraWork || {}), [action.playerId]: ((state.extraWork || {})[action.playerId] || []).filter((e) => e.id !== action.entryId) } };
    case "UPDATE_FIXTURE":
      return { ...state, fixtures: state.fixtures.map((f) => f.id === action.id ? { ...f, ...action.patch } : f) };
    case "UPDATE_SESSION":
      return { ...state, sessions: state.sessions.map((s) => s.id === action.id ? { ...s, ...action.patch } : s) };
    case "TOGGLE_INJURY":
      return { ...state, players: state.players.map((p) => p.id === action.id ? { ...p, injured: !p.injured } : p) };

    case "ADD_FIXTURE": {
      const id = "f" + Date.now();
      return { ...state, fixtures: [...state.fixtures, { id, teamId: state.activeTeamId, status: "scheduled", ...action.fixture }] };
    }
    case "DELETE_FIXTURE": {
      const lineups = { ...state.lineups }; delete lineups[action.id];
      const events = { ...state.events }; delete events[action.id];
      const availability = { ...state.availability }; delete availability[action.id];
      const liveMatches = { ...(state.liveMatches || {}) }; delete liveMatches[action.id];
      return { ...state, fixtures: state.fixtures.filter((f) => f.id !== action.id), lineups, events, availability, liveMatches };
    }
    case "ADD_SESSION": {
      const id = "s" + Date.now();
      return { ...state, sessions: [...state.sessions, { id, teamId: state.activeTeamId, ...action.session }] };
    }
    case "DELETE_SESSION": {
      const attendance = { ...state.attendance }; delete attendance[action.id];
      const availability = { ...state.availability }; delete availability[action.id];
      return { ...state, sessions: state.sessions.filter((s) => s.id !== action.id), attendance, availability };
    }

    case "SET_LINEUP": return { ...state, lineups: { ...state.lineups, [action.fixtureId]: action.lineup } };
    case "SET_ATTENDANCE": return { ...state, attendance: { ...state.attendance, [action.id]: action.map } };
    case "SET_AVAILABILITY": return { ...state, availability: { ...state.availability, [action.id]: action.map } };
    case "SET_SUB_ORDER": return { ...state, subOrders: { ...(state.subOrders || {}), [action.fixtureId]: action.order } };

    case "COMPLETE_MATCH":
      return {
        ...state,
        events: { ...state.events, [action.fixtureId]: action.events },
        fixtures: state.fixtures.map((f) => f.id === action.fixtureId ? { ...f, status: "completed", result: action.result, ht: action.ht || null, fullClock: action.fullClock || 0, completedAt: Date.now() } : f),
      };
    // Re-open a completed match for editing: restore a live session from the saved
    // result + feed and flip the fixture back to in-progress.
    case "REOPEN_MATCH": {
      const f = state.fixtures.find((x) => x.id === action.id);
      if (!f) return state;
      const lu = state.lineups[action.id] || {};
      const starters = GAA_POSITIONS.map((pos) => lu[pos.no]).filter(Boolean);
      const live = { score: f.result || { home: { g: 0, p: 0 }, away: { g: 0, p: 0 } }, clock: f.fullClock || 0, half: f.ht ? "H2" : "H1", events: state.events[action.id] || [], onPitch: starters, ht: f.ht || null };
      return { ...state, liveMatches: { ...state.liveMatches, [action.id]: live }, fixtures: state.fixtures.map((x) => x.id === action.id ? { ...x, status: "scheduled" } : x) };
    }
    // Wipe a match back to a clean scheduled fixture (clears score, feed, POTM).
    case "RESET_MATCH": {
      const events = { ...state.events }; delete events[action.id];
      const liveMatches = { ...state.liveMatches }; delete liveMatches[action.id];
      return { ...state, events, liveMatches, fixtures: state.fixtures.map((f) => f.id === action.id ? { ...f, status: "scheduled", result: undefined, ht: undefined, fullClock: undefined, potm: undefined } : f) };
    }
    default: return state;
  }
}

