const fmtScore = (g, p) => `${g}-${String(p).padStart(2, "0")}`;
const totalPts = (g, p) => g * 3 + p;
const fmtDate = (iso) => new Date(iso).toLocaleDateString("en-IE", { weekday: "short", day: "numeric", month: "short" });
const fmtTime = (iso) => new Date(iso).toLocaleTimeString("en-IE", { hour: "2-digit", minute: "2-digit" });
const fmtClock = (s) => `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
const initials = (name = "") => name.trim().split(/\s+/).map((w) => w[0]).slice(0, 2).join("").toUpperCase();
const surname = (name = "") => name.trim().split(/\s+/).slice(-1)[0] || "";
const forename = (name = "") => { const t = name.trim().split(/\s+/); return t.length > 1 ? t.slice(0, -1).join(" ") : (t[0] || ""); };
// Left / centre / right columns share the same x across every line so the
// full-backs sit directly behind the half-backs, half-forwards, etc.
const PITCH_COORDS = {
  1: { x: 0.5, y: 0.92 },
  2: { x: 0.80, y: 0.80 }, 3: { x: 0.5, y: 0.80 }, 4: { x: 0.20, y: 0.80 },
  5: { x: 0.80, y: 0.64 }, 6: { x: 0.5, y: 0.64 }, 7: { x: 0.20, y: 0.64 },
  8: { x: 0.38, y: 0.50 }, 9: { x: 0.62, y: 0.50 },
  10: { x: 0.80, y: 0.34 }, 11: { x: 0.5, y: 0.34 }, 12: { x: 0.20, y: 0.34 },
  13: { x: 0.80, y: 0.18 }, 14: { x: 0.5, y: 0.18 }, 15: { x: 0.20, y: 0.18 },
};
const startOfDay = (x) => { const y = new Date(x); y.setHours(0, 0, 0, 0); return y; };
function countdown(dateIso) {
  const now = new Date(); const d = new Date(dateIso);
  if (d - now < 0) return "past";
  const days = Math.round((startOfDay(d) - startOfDay(now)) / 86400000);
  if (days === 0) return "today";
  if (days === 1) return "tomorrow";
  return `in ${days} days`;
}
const MAIN_TABS = ["dashboard", "players", "fixtures", "training", "reports"];
const toLocalInput = (iso) => { const d = new Date(iso); const local = new Date(d.getTime() - d.getTimezoneOffset() * 60000); return local.toISOString().slice(0, 16); };
const fromLocalInput = (val) => new Date(val).toISOString();
const COLOR_PRESETS = [
  { name: "Black & Red", primary: "#18181b", accent: "#dc2626" },
  { name: "Green & Gold", primary: "#15803d", accent: "#f59e0b" },
  { name: "Blue & White", primary: "#1d4ed8", accent: "#60a5fa" },
  { name: "Maroon", primary: "#7f1d1d", accent: "#ef4444" },
  { name: "Green & Red", primary: "#166534", accent: "#dc2626" },
  { name: "Amber & Black", primary: "#b45309", accent: "#111827" },
  { name: "Purple & Gold", primary: "#6b21a8", accent: "#f59e0b" },
  { name: "Navy & Sky", primary: "#0c4a6e", accent: "#0ea5e9" },
];
const DEFAULT_SETTINGS = { throwInTime: "19:30", homeVenue: "Middletown GAA Grounds", theme: { primary: "#18181b", accent: "#dc2626", alternative: "#ffffff" }, lastBackup: null, largeText: false };
// light haptic tap (no-op where unsupported, e.g. iOS Safari)
const buzz = (ms = 12) => { try { if (navigator.vibrate) navigator.vibrate(ms); } catch (_) {} };

const xmlEsc = (s = "") => String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

// Read an uploaded image and shrink it to a small PNG data URL so it fits in the
// phone's limited storage while still looking crisp on the poster (rendered ~92px
// at 2x). Kept small on purpose — many crest/jersey images can add up fast.
function fileToImageDataUrl(file, max = 256) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, max / Math.max(img.width, img.height));
        const w = Math.max(1, Math.round(img.width * scale)), h = Math.max(1, Math.round(img.height * scale));
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        try { resolve(canvas.toDataURL("image/png")); } catch (e) { reject(e); }
      };
      img.onerror = reject;
      img.src = String(reader.result);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// Rasterise an SVG string to a PNG and share it via the share sheet (falling
// back to a download). Used to share a clean teamsheet / report image.
async function shareImage(svg, filename, w, h) {
  return new Promise((resolve) => {
    try {
      const url = URL.createObjectURL(new Blob([svg], { type: "image/svg+xml;charset=utf-8" }));
      const img = new Image();
      img.onload = () => {
        const scale = 2;
        const canvas = document.createElement("canvas");
        canvas.width = w * scale; canvas.height = h * scale;
        const ctx = canvas.getContext("2d");
        ctx.scale(scale, scale); ctx.drawImage(img, 0, 0);
        URL.revokeObjectURL(url);
        canvas.toBlob(async (png) => {
          if (!png) { resolve(false); return; }
          const file = new File([png], filename, { type: "image/png" });
          try {
            if (navigator.canShare && navigator.canShare({ files: [file] })) { await navigator.share({ files: [file] }); resolve(true); return; }
          } catch (e) { if (e && e.name === "AbortError") { resolve(false); return; } }
          try {
            const a = document.createElement("a"); a.href = URL.createObjectURL(png); a.download = filename;
            document.body.appendChild(a); a.click(); a.remove(); resolve(true);
          } catch (_) { resolve(false); }
        }, "image/png");
      };
      img.onerror = () => { URL.revokeObjectURL(url); resolve(false); };
      img.src = url;
    } catch (_) { resolve(false); }
  });
}

async function downloadBackupFile(state) {
  const json = JSON.stringify(state, null, 2);
  const filename = `panelpro-backup-${new Date().toISOString().slice(0, 10)}.json`;
  // Prefer the share sheet with a real file — lets you send the backup to
  // email / WhatsApp / Files straight from the phone.
  try {
    if (navigator.canShare) {
      const file = new File([json], filename, { type: "application/json" });
      if (navigator.canShare({ files: [file] })) { await navigator.share({ files: [file], title: "PanelPro backup" }); return true; }
    }
  } catch (e) {
    if (e && e.name === "AbortError") return false; // user closed the share sheet
    // otherwise fall through to a plain download
  }
  try {
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);
    return true;
  } catch (_) { return false; }
}
const themeOf = (state) => (state.settings && state.settings.theme) || DEFAULT_SETTINGS.theme;
const shade = (hex, amt = -18) => {
  const n = parseInt(hex.slice(1), 16);
  const clamp = (v) => Math.max(0, Math.min(255, v));
  const r = clamp((n >> 16) + amt), g = clamp(((n >> 8) & 255) + amt), b = clamp((n & 255) + amt);
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};
const tint = (hex, a) => { const n = parseInt(hex.slice(1), 16); return `rgba(${(n >> 16) & 255},${(n >> 8) & 255},${n & 255},${a})`; };
function nextDateAt(daysAhead, hhmm = "19:30") {
  const [hh, mm] = hhmm.split(":").map(Number);
  const d = new Date(); d.setDate(d.getDate() + daysAhead); d.setHours(hh || 19, mm || 30, 0, 0); return d.toISOString();
}

function teamData(state) {
  const team = state.teams.find((t) => t.id === state.activeTeamId) || state.teams[0];
  return {
    team,
    players: state.players.filter((p) => p.teamId === team.id),
    fixtures: state.fixtures.filter((f) => f.teamId === team.id),
    sessions: state.sessions.filter((s) => s.teamId === team.id),
  };
}

// aggregate scorers from an events array (home/our side only)
function summarizeScorers(events = [], nameOf) {
  const map = {};
  events.filter((e) => e.side === "HOME" && (e.playerId || e.player)).forEach((e) => {
    const key = e.playerId || e.player;
    const nm = (nameOf && e.playerId && nameOf(e.playerId)) || e.player || "Unknown";
    const m = map[key] || (map[key] = { id: e.playerId || null, name: nm, goals: 0, points: 0, frees: 0, wides: 0 });
    if (e.type === "Goal") m.goals++;
    else if (e.type === "Point") m.points++;
    else if (e.type === "Free Converted") { m.points++; m.frees++; } // legacy
    else if (e.type === "Wide") m.wides++;
    if (e.score && e.detail === "Free") m.frees++;
  });
  return Object.values(map)
    .filter((m) => m.goals || m.points || m.wides)
    .sort((a, b) => totalPts(b.goals, b.points) - totalPts(a.goals, a.points));
}

/* ============================ root ============================ */

export default function App() {
  const [state, dispatch] = useReducer(reducer, undefined, makeSeed);
  const [hydrated, setHydrated] = useState(false);
  const [stack, setStack] = useState([{ screen: "teamSelect" }]);
  const [toast, setToast] = useState(null);
  const [needRefresh, setNeedRefresh] = useState(false);
  const [storageOk, setStorageOk] = useState(true);
  const [cloudUser, setCloudUser] = useState(null);
  const updateSWRef = useRef(null);
  const cloudPulledRef = useRef(false);
  const cloudPushTimer = useRef(null);

  // PWA: when a new version is deployed, prompt to refresh instead of silently updating
  useEffect(() => {
    let mounted = true;
    import("virtual:pwa-register")
      .then(({ registerSW }) => {
        updateSWRef.current = registerSW({ onNeedRefresh() { if (mounted) setNeedRefresh(true); } });
      })
      .catch(() => {});
    return () => { mounted = false; };
  }, []);

  // load persisted state on mount
  useEffect(() => {
    let active = true;
    (async () => {
      const raw = await store.get(STORE_KEY);
      if (active && raw) {
        try {
          const parsed = JSON.parse(raw);
          if (parsed && parsed.version === 1 && Array.isArray(parsed.teams)) {
            parsed.players = (parsed.players || []).map((p) => {
              const role = p.role || defaultRole(p.group);
              return { ...p, role, group: groupOfRole(role) };
            });
            parsed.settings = { ...DEFAULT_SETTINGS, ...(parsed.settings || {}) };
            parsed.hints = parsed.hints || {};
            parsed.liveMatches = parsed.liveMatches || {};
            parsed.extraWork = parsed.extraWork || {};
            parsed.teams = withSeedClub(parsed.teams);
            // in-place migration — upgrade old data, never discard it
            if (parsed.events) {
              Object.keys(parsed.events).forEach((fid) => {
                const fx = (parsed.fixtures || []).find((f) => f.id === fid);
                const teamId = fx ? fx.teamId : null;
                parsed.events[fid] = (parsed.events[fid] || []).map((e) => {
                  if (e.playerId || !e.player) return e;
                  const p = (parsed.players || []).find((x) => x.name === e.player && (!teamId || x.teamId === teamId));
                  return { ...e, playerId: p ? p.id : null };
                });
              });
            }
            dispatch({ type: "HYDRATE", state: parsed });
          }
        } catch (_) {}
      }
      if (active) setHydrated(true);
    })();
    return () => { active = false; };
  }, []);

  // persist on change (after hydration). If the write fails (storage full) flag it
  // so the user is warned instead of losing data silently.
  useEffect(() => {
    if (hydrated) store.set(STORE_KEY, JSON.stringify(state)).then((ok) => setStorageOk(ok !== false));
  }, [state, hydrated]);

  // ---- optional cloud sync (inert unless VITE_SUPABASE_* are set) ----------
  // Track sign-in/out. Does nothing when cloud sync isn't configured.
  useEffect(() => {
    if (!cloudConfigured()) return;
    let unsub = () => {};
    currentUser().then(setCloudUser);
    onAuthChange((u) => { cloudPulledRef.current = false; setCloudUser(u); }).then((fn) => { unsub = fn; });
    return () => unsub();
  }, []);

  // On sign-in, pull the cloud copy once and adopt it if one exists; otherwise
  // seed the cloud from this device. Last-write-wins on the whole state blob.
  useEffect(() => {
    if (!cloudConfigured() || !cloudUser || !hydrated || cloudPulledRef.current) return;
    cloudPulledRef.current = true;
    (async () => {
      const remote = await pullState();
      if (remote && remote.state && Array.isArray(remote.state.teams)) {
        dispatch({ type: "HYDRATE", state: { ...remote.state, settings: { ...DEFAULT_SETTINGS, ...(remote.state.settings || {}) } } });
      } else {
        pushState(state);
      }
    })();
  }, [cloudUser, hydrated]); // eslint-disable-line react-hooks/exhaustive-deps

  // Push changes up (debounced) while signed in.
  useEffect(() => {
    if (!cloudConfigured() || !cloudUser || !hydrated || !cloudPulledRef.current) return;
    clearTimeout(cloudPushTimer.current);
    cloudPushTimer.current = setTimeout(() => pushState(state), 1500);
    return () => clearTimeout(cloudPushTimer.current);
  }, [state, cloudUser, hydrated]);

  // Always points at the freshest state so a backup fired from a toast action
  // (e.g. straight after completing a match) includes the change that triggered it.
  const stateRef = useRef(state);
  stateRef.current = state;

  const view = stack[stack.length - 1];
  const nav = {
    view,
    push: (screen, params = {}) => setStack((s) => [...s, { screen, ...params }]),
    pop: () => setStack((s) => (s.length > 1 ? s.slice(0, -1) : s)),
    reset: (screen, params = {}) => setStack([{ screen, ...params }]),
    toast: (message, action) => setToast({ message, action, id: Date.now() }),
    backup: async () => {
      const ok = await downloadBackupFile(stateRef.current);
      if (ok) dispatch({ type: "SET_SETTINGS", patch: { lastBackup: Date.now() } });
      setToast({ message: ok ? "Backup saved" : "Couldn't save file — use Settings → Copy backup", id: Date.now() });
      return ok;
    },
  };

  return (
    <div className="min-h-screen w-full bg-zinc-200 flex items-center justify-center font-sans">
      <div className="relative w-full sm:max-w-[420px] h-screen sm:h-[860px] bg-zinc-50 sm:rounded-[40px] overflow-hidden shadow-2xl sm:border-[10px] sm:border-black flex flex-col" style={state.settings?.largeText ? { fontSize: "112.5%", zoom: 1.08 } : undefined}>
        {!hydrated ? (
          <div className="flex-1 flex flex-col items-center justify-center gap-4 bg-black text-white">
            <img src={LOGO} alt="ProPanel" className="w-28 h-28 rounded-2xl object-cover" />
            <p className="text-sm text-zinc-400">Loading…</p>
          </div>
        ) : (
          <>
            {!storageOk && (
              <div className="bg-red-600 text-white px-4 py-2.5 flex items-start gap-2" style={{ paddingTop: "max(0.625rem, env(safe-area-inset-top))" }}>
                <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
                <p className="text-[12px] leading-snug font-medium">Storage is full — recent changes may not be saving. Export a backup now, then remove some crest/jersey images to free space.</p>
              </div>
            )}
            <div className="flex-1 min-h-0 flex flex-col">
              <Router state={state} dispatch={dispatch} nav={nav} />
            </div>
            {MAIN_TABS.includes(view.screen) && <TabBar current={view.screen} go={(scr) => nav.reset(scr)} color={themeOf(state).primary} />}
            <Toast toast={toast} onClose={() => setToast(null)} />
            {needRefresh && (
              <div className="absolute left-0 right-0 bottom-28 flex justify-center px-4 z-[80] pointer-events-none">
                <div className="pointer-events-auto bg-emerald-600 text-white rounded-full pl-4 pr-2 py-2 flex items-center gap-3 shadow-xl">
                  <span className="text-[13px] font-semibold flex items-center gap-1.5"><Sparkles className="w-4 h-4" /> New version ready</span>
                  <button onClick={() => { const u = updateSWRef.current; setNeedRefresh(false); if (u) u(true); else location.reload(); }} className="bg-white text-emerald-700 text-[12px] font-bold px-3 py-1.5 rounded-full active:scale-95">Refresh</button>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

function Router({ state, dispatch, nav }) {
  const { view } = nav;
  switch (view.screen) {
    case "teamSelect": return <TeamSelect state={state} dispatch={dispatch} nav={nav} />;
    case "dashboard": return <Dashboard state={state} dispatch={dispatch} nav={nav} />;
    case "players": return <Players state={state} dispatch={dispatch} nav={nav} initialFilter={view.filter} />;
    case "fixtures": return <Fixtures state={state} dispatch={dispatch} nav={nav} initialTab={view.tab} />;
    case "fixtureDetail": return <FixtureDetail state={state} nav={nav} fixtureId={view.fixtureId} />;
    case "lineup": return <Lineup state={state} dispatch={dispatch} nav={nav} fixtureId={view.fixtureId} />;
    case "live": return <LiveMatch state={state} dispatch={dispatch} nav={nav} fixtureId={view.fixtureId} />;
    case "training": return <Training state={state} dispatch={dispatch} nav={nav} />;
    case "attendance": return <Attendance state={state} dispatch={dispatch} nav={nav} sessionId={view.sessionId} />;
    case "availability": return <Availability state={state} dispatch={dispatch} nav={nav} fixtureId={view.fixtureId} />;
    case "reports": return <Reports state={state} nav={nav} />;
    case "matchReport": return <MatchReport state={state} dispatch={dispatch} nav={nav} fixtureId={view.fixtureId} />;
    case "playerStats": return <PlayerStats state={state} nav={nav} />;
    case "seasonBreakdown": return <SeasonBreakdown state={state} nav={nav} kind={view.kind} />;
    case "seasonStat": return <SeasonStat state={state} nav={nav} cat={view.cat} />;
    case "playerProfile": return <PlayerProfile state={state} dispatch={dispatch} nav={nav} playerId={view.playerId} />;
    case "settings": return <SettingsScreen state={state} dispatch={dispatch} nav={nav} />;
    case "calendar": return <Calendar state={state} nav={nav} />;
    default: return <Dashboard state={state} dispatch={dispatch} nav={nav} />;
  }
}

