function SwipeRow({ children, onDelete, radius = "rounded-2xl" }) {
  const [offset, setOffset] = useState(0);
  const [dragging, setDragging] = useState(false);
  const startX = useRef(0), base = useRef(0), offsetRef = useRef(0), moved = useRef(false), suppress = useRef(false);
  const ACTION = 88, FULL = 150;
  const set = (v) => { offsetRef.current = v; setOffset(v); };
  const down = (e) => { startX.current = e.clientX; base.current = offsetRef.current; moved.current = false; setDragging(true); };
  const move = (e) => {
    if (!dragging) return;
    const dx = e.clientX - startX.current;
    if (!moved.current && Math.abs(dx) < 6) return;
    moved.current = true;
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
    let next = base.current + dx;
    if (next > 0) next = 0;
    if (next < -(ACTION + 48)) next = -(ACTION + 48);
    set(next);
  };
  const up = () => {
    setDragging(false);
    if (!moved.current) return;
    suppress.current = true;
    const o = offsetRef.current;
    if (o <= -FULL) { set(0); onDelete(); }
    else if (o <= -ACTION / 2) set(-ACTION);
    else set(0);
  };
  const onClickCapture = (e) => {
    if (offsetRef.current !== 0) { e.stopPropagation(); e.preventDefault(); set(0); suppress.current = false; return; }
    if (suppress.current) { e.stopPropagation(); e.preventDefault(); suppress.current = false; }
  };
  return (
    <div className={`relative overflow-hidden ${radius}`}>
      <div className={`absolute inset-0 bg-red-600 flex items-center justify-end pr-6 ${radius}`}>
        <button onClick={() => { set(0); onDelete(); }} className="flex flex-col items-center text-white active:scale-90">
          <Trash2 className="w-5 h-5" /><span className="text-[11px] font-bold mt-0.5">Delete</span>
        </button>
      </div>
      <div onPointerDown={down} onPointerMove={move} onPointerUp={up} onPointerCancel={up} onClickCapture={onClickCapture}
        style={{ transform: `translateX(${offset}px)`, touchAction: "pan-y" }}
        className={`relative ${dragging ? "" : "transition-transform duration-200"}`}>
        {children}
      </div>
    </div>
  );
}

