function Dashboard({ state, dispatch, nav }) {
  const { team, players, fixtures, sessions } = teamData(state);
  const [switching, setSwitching] = useState(false);
  const [hideBackup, setHideBackup] = useState(false);

  const injured = players.filter((p) => p.injured).length;
  const completed = fixtures.filter((f) => f.status === "completed").length;
  const upcomingFixtures = fixtures.filter((f) => f.status !== "completed").sort((a, b) => new Date(a.date) - new Date(b.date));
  const upcomingSessions = sessions.filter((s) => new Date(s.date) > new Date()).sort((a, b) => new Date(a.date) - new Date(b.date));
  const nextFixture = upcomingFixtures[0];
  // The next two events overall — game or training — in chronological order.
  const nextEvents = [
    ...upcomingFixtures.map((f) => ({ kind: "fixture", date: f.date, data: f })),
    ...upcomingSessions.map((s) => ({ kind: "session", date: s.date, data: s })),
  ].sort((a, b) => new Date(a.date) - new Date(b.date)).slice(0, 2);
  const theme = themeOf(state);
  const { primary, accent } = theme;
  const completedFx = fixtures.filter((f) => f.status === "completed");
  const resultOf = (f) => { const h = totalPts(f.result.home.g, f.result.home.p), a = totalPts(f.result.away.g, f.result.away.p); return h > a ? "W" : h < a ? "L" : "D"; };
  const rec = { W: 0, D: 0, L: 0 }; completedFx.forEach((f) => rec[resultOf(f)]++);
  const form = [...completedFx].sort((a, b) => new Date(a.date) - new Date(b.date)).slice(-5).map(resultOf);
  const lastBackup = state.settings && state.settings.lastBackup;
  const daysSince = lastBackup ? Math.floor((Date.now() - lastBackup) / 86400000) : null;
  // Nudge weekly, and again straight after any match is completed (its result is
  // the data you'd most hate to lose).
  const matchSinceBackup = completedFx.some((f) => f.completedAt && f.completedAt > (lastBackup || 0));
  const needBackup = !hideBackup && (players.length > 0 || completedFx.length > 0) && (!lastBackup || daysSince >= 7 || matchSinceBackup);
  const backupNow = async () => { const ok = await downloadBackupFile(state); if (ok) { dispatch({ type: "SET_SETTINGS", patch: { lastBackup: Date.now() } }); nav.toast("Backup saved"); } };

  const handleAction = (to) => {
    if (to === "lineupPick" || to === "matchPick") {
      if (nextFixture) nav.push(to === "lineupPick" ? "lineup" : "live", { fixtureId: nextFixture.id });
      else nav.reset("fixtures");
    } else nav.reset(to);
  };

  const actions = [
    { label: "Players", icon: Users, to: "players" },
    { label: "Create Fixture", icon: Plus, to: "fixtures" },
    { label: "Team Line Out", icon: ClipboardList, to: "lineupPick" },
    { label: "Training", icon: Dumbbell, to: "training" },
    { label: "Start Match", icon: Activity, to: "matchPick" },
    { label: "Reports", icon: BarChart3, to: "reports" },
  ];

  return (
    <div className="flex flex-col h-full">
      <StatusBar />
      <Header title={team.name} right={<div className="flex items-center gap-1"><button onClick={() => nav.push("calendar")} aria-label="Calendar" className="p-1.5 rounded-full active:bg-zinc-100"><CalendarDays className="w-5 h-5 text-zinc-700" /></button><button onClick={() => nav.push("settings")} aria-label="Settings" className="p-1.5 rounded-full active:bg-zinc-100"><Settings className="w-5 h-5 text-zinc-700" /></button></div>} />
      <div className="flex-1 overflow-y-auto pb-6">
        {/* hero */}
        <div className="text-white px-5 pt-5 pb-6" style={{ background: `linear-gradient(160deg, ${primary}, ${shade(primary, -30)})` }}>
          <div className="flex items-start gap-3">
            <button onClick={() => setSwitching(true)} className="flex items-center gap-3 text-left flex-1 min-w-0">
              <div className="w-16 h-16 rounded-2xl bg-white flex items-center justify-center overflow-hidden shrink-0">
                <img src={team.crest || LOGO} alt="" className="w-14 h-14 object-contain" />
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-[12px] text-white/60 truncate">{clubShortOf(team)} GAA{clubIrishOf(team) ? <> · <span className="italic">{clubIrishOf(team)}</span></> : null}</p>
                <h2 className="text-2xl font-black leading-tight flex items-center gap-1">{team.name}<ChevronDown className="w-5 h-5 text-white/50 shrink-0" /></h2>
                <div className="flex gap-1.5 mt-1.5 flex-wrap">
                  {teamBadges(team).map((b, i) => (
                    <span key={i} className="text-[10px] font-semibold bg-white/15 px-2 py-0.5 rounded-full">{b}</span>
                  ))}
                </div>
              </div>
            </button>
            {completedFx.length > 0 && (
              <div className="text-right shrink-0">
                <p className="text-[10px] text-white/50 uppercase tracking-wide">Record</p>
                <p className="font-black text-[16px] tabular-nums">{rec.W}-{rec.D}-{rec.L}</p>
                {form.length > 0 && (
                  <div className="flex gap-1 justify-end mt-1">
                    {form.map((r, i) => (
                      <span key={i} className="w-3.5 h-3.5 rounded-[3px] flex items-center justify-center text-[7px] font-black text-white" style={{ background: r === "W" ? "#16a34a" : r === "L" ? "#dc2626" : "#a1a1aa" }}>{r}</span>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
          <div className="grid grid-cols-4 gap-2 mt-5">
            <HeroStat value={players.length} label="Players" onClick={() => nav.reset("players")} />
            <HeroStat value={injured} label="Injured" danger={injured > 0} onClick={() => nav.reset("players", { filter: "injured" })} />
            <HeroStat value={upcomingSessions.length} label="Sessions" onClick={() => nav.reset("training")} />
            <HeroStat value={completed} label="Played" onClick={() => nav.reset("fixtures", { tab: "past" })} />
          </div>
        </div>

        {needBackup && (
          <div className="px-4 pt-4">
            <div className="flex items-center gap-2 bg-amber-50 border border-amber-200 rounded-2xl px-3 py-2.5">
              <Download className="w-4 h-4 text-amber-700 shrink-0" />
              <p className="text-[12px] text-amber-800 flex-1 leading-snug">{matchSinceBackup && (daysSince === null || daysSince < 7) ? "You've a new match result to protect." : lastBackup ? `Last backup ${daysSince} day${daysSince === 1 ? "" : "s"} ago.` : "You haven't backed up yet."} Keep your season safe.</p>
              <button onClick={backupNow} className="shrink-0 text-[12px] font-bold text-white bg-amber-600 px-3 py-1.5 rounded-full active:scale-95">Back up</button>
              <button onClick={() => setHideBackup(true)} aria-label="Dismiss" className="shrink-0 text-amber-700 p-0.5"><X className="w-4 h-4" /></button>
            </div>
          </div>
        )}

        {/* next up */}
        <div className="px-4 pt-5">
          <p className="text-[13px] font-bold text-zinc-500 uppercase tracking-wide mb-3">Next up</p>
          {nextEvents.length ? (
            <div className="space-y-2.5">
              {nextEvents.map((ev, i) => (
                ev.kind === "fixture"
                  ? (i === 0
                      ? <NextFixtureCard key={ev.data.id} state={state} nav={nav} fixture={ev.data} accent={accent} />
                      : <CompactFixtureCard key={ev.data.id} nav={nav} fixture={ev.data} accent={accent} />)
                  : <CompactSessionCard key={ev.data.id} nav={nav} session={ev.data} />
              ))}
            </div>
          ) : (
            <Empty text="Nothing scheduled" icon={Trophy} actionLabel="Add a fixture" onAction={() => nav.reset("fixtures")} />
          )}
        </div>

        {/* quick actions */}
        <div className="px-4 pt-6">
          <p className="text-[13px] font-bold text-zinc-500 uppercase tracking-wide mb-3">Quick actions</p>
          <div className="grid grid-cols-3 gap-3">
            {actions.map((a) => (
              <button key={a.label} onClick={() => handleAction(a.to)} className="bg-white border border-zinc-200 rounded-2xl py-4 flex flex-col items-center gap-2 active:scale-95 transition-transform">
                <a.icon className="w-6 h-6 text-zinc-900" strokeWidth={1.75} />
                <span className="text-[12px] font-semibold text-zinc-700 text-center leading-tight px-1">{a.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {switching && <TeamSwitcher state={state} dispatch={dispatch} onClose={() => setSwitching(false)} />}
    </div>
  );
}

function HeroStat({ value, label, danger, onClick }) {
  return (
    <button onClick={onClick} className="bg-white/5 rounded-xl py-2.5 flex flex-col items-center active:bg-white/10 transition-colors">
      <span className={`text-xl font-black tabular-nums ${danger ? "text-red-400" : "text-white"}`}>{value}</span>
      <span className="text-[10px] text-zinc-400 mt-0.5">{label}</span>
    </button>
  );
}

function TeamSwitcher({ state, dispatch, onClose }) {
  const [adding, setAdding] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const counts = (id) => state.players.filter((p) => p.teamId === id).length;
  return (
    <Sheet title="Teams" onClose={onClose}>
      <div className="space-y-2 -mt-1">
        {state.teams.map((t) => {
          const active = t.id === state.activeTeamId;
          return (
            <button key={t.id} onClick={() => { dispatch({ type: "SET_ACTIVE_TEAM", id: t.id }); onClose(); }}
              className={`w-full flex items-center gap-3 p-3 rounded-2xl border ${active ? "border-black bg-zinc-50" : "border-zinc-200 bg-white"}`}>
              <div className="w-10 h-10 rounded-xl bg-white border border-zinc-200 flex items-center justify-center overflow-hidden">
                <img src={t.crest || LOGO} alt="" className="w-8 h-8 object-contain" />
              </div>
              <div className="flex-1 text-left">
                <p className="font-bold text-[15px] text-zinc-900">{t.name}</p>
                <p className="text-[12px] text-zinc-500">{[t.sport, t.grade].filter(Boolean).join(" · ")} · {counts(t.id)} players</p>
              </div>
              {active && <Check className="w-5 h-5 text-black" />}
            </button>
          );
        })}
      </div>
      <button onClick={() => setAdding(true)} className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl border border-dashed border-zinc-300 text-zinc-600 font-semibold text-[14px]">
        <Plus className="w-4 h-4" /> Add a team
      </button>
      <button onClick={() => setConfirmReset(true)} className="w-full text-center text-[12px] text-zinc-400 pt-1">Reset all demo data</button>

      {adding && <AddTeam onClose={() => setAdding(false)} onSave={(team) => { dispatch({ type: "ADD_TEAM", team }); setAdding(false); onClose(); }} />}
      {confirmReset && (
        <Confirm title="Reset everything?" confirmLabel="Reset"
          message="This restores the original demo teams, roster and fixtures. Anything you've added will be lost."
          onConfirm={() => { dispatch({ type: "RESET" }); setConfirmReset(false); onClose(); }}
          onClose={() => setConfirmReset(false)} />
      )}
    </Sheet>
  );
}

// Landing screen shown when the app opens — pick which team to manage, or add one.
